     STRPGMEXP PGMLVL(*CURRENT) SIGNATURE('Version 1.5')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_delete')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_getNumE')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_new')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_rtvFldAtr')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_isNull')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_null')
     ENDPGMEXP

     STRPGMEXP PGMLVL(*PRV    ) SIGNATURE(*GEN)
       EXPORT SYMBOL('RTVFLDA_f_FldDct_delete')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_getNumE')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_new')
       EXPORT SYMBOL('RTVFLDA_f_FldDct_rtvFldAtr')
     ENDPGMEXP

