      *     >>EXECUTE<<                                                     *
      *                                                                     *
      *     >>CMD<<     CRTPGM       PGM(&LI/&OB) +                         *
      *                              MODULE(*PGM) +                         *
      *                              BNDSRVPGM(&LI/RTVFLDA BASICS1) +       *
      *                              ACTGRP(*NEW) +                         *
      *                              DETAIL(*BASIC);                        *
      *                                                                     *
      *   >>END-PRE-COMPILER<<                                              *
      *=====================================================================*
     H EXTBININT(*YES)
     H DATFMT(*ISO) TIMFMT(*ISO) DEBUG(*YES)
      *=====================================================================*
      *
      /COPY QRTVFLDA,PRTVFLDA
      *
      *  *ENTRY list
     D RTVFLDA_T...
     D                 PR                  extpgm('RTVFLDA_T2')
     D  gi_file                      10A   const
     D  gi_fldName                   10A   const
      *
      *  Internal prototypes
     D main...
     D                 PR
     D  i_file                       10A   const
     D  i_fldName                    10A   const
      *
      ********************************************************************
      *  Program Entry Point
      ********************************************************************
      *
     D RTVFLDA_T...
     D                 PI
     D  gi_file                      10A   const
     D  gi_fldName                   10A   const
      *-------------------------------------------------------------------
      /FREE
         main(gi_file: gi_fldName);

         *inlr = *ON;

      /END-FREE
      *
      *==================================================================*
      *  Main procedure
      *==================================================================*
     P main...
     P                 B                   export
     D                 PI
     D  i_file                       10A   const
     D  i_fldName                    10A   const
      *
      *  Local fields
     D isOK            S               N   inz
     D handle          S                   like(fldDct_handle_t) inz
      *
     D msg             DS                  likeds(msg_t        ) inz
     D errMsg          DS                  likeds(msg_t        ) inz
     D flda0200        DS                  likeds(flda0200_t   ) inz
      *-------------------------------------------------------------------
      /FREE

         errMsg = f_newMsg(cMSG_ID_OK);

         dou '1';

            // Open dictionary
            isOK = f_fldDct_new(i_file: '*LIBL': '*FIRST': handle: msg);

            // Get attributes of i_fldName
            isOK = f_FldDct_rtvFldAtr(handle: i_fldName: flda0200: 'FLDA0200');
            if (isOK);
               msg = f_newMsg('CPF9897'
                              : 'Field ' + %trim(flda0200.name) +
                                ', REFFLD(' + %trim(FLDA0200.REFFLD) + ')');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            else;
               errMsg = f_newMsg('CPF9898'
                              : 'Field not found'
                              : cMSG_ESCAPE);
               leave;
            endif;

            // Get attributes of previous field
            isOK = f_FldDct_rtvFldAtr(
                            handle: cFLDDCT_FLD_PREV: flda0200: 'FLDA0200');
            if (isOK);
               msg = f_newMsg('CPF9897'
                              : 'Previous field ' + %trim(flda0200.name) +
                                ', REFFLD(' + %trim(FLDA0200.REFFLD) + ')');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            else;
               msg = f_newMsg('CPF9897'
                              : i_fldName +
                                ' is the first field of the record.');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            endif;

            // Position back to i_fldName
            isOK = f_FldDct_rtvFldAtr(handle: i_fldName: flda0200: 'FLDA0200');

            // Get attributes of next field
            isOK = f_FldDct_rtvFldAtr(
                            handle: cFLDDCT_FLD_NEXT: flda0200: 'FLDA0200');
            if (isOK);
               msg = f_newMsg('CPF9897'
                              : 'Next field ' + %trim(flda0200.name) +
                                ', REFFLD(' + %trim(FLDA0200.REFFLD) + ')');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            else;
               msg = f_newMsg('CPF9897'
                              : i_fldName +
                                ' is the last field of the record.');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            endif;

            // Get attributes of first field of record
            isOK = f_FldDct_rtvFldAtr(
                            handle: cFLDDCT_FLD_FIRST: flda0200: 'FLDA0200');
            if (isOK);
               msg = f_newMsg('CPF9897'
                              : 'First field ' + %trim(flda0200.name) +
                                ', REFFLD(' + %trim(FLDA0200.REFFLD) + ')');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            else;
               msg = f_newMsg('CPF9898'
                              : 'Failed retrieving attributes of first field'
                              : cMSG_ESCAPE);
               leave;
            endif;

            // Get attributes of last field of record
            isOK = f_FldDct_rtvFldAtr(
                            handle: cFLDDCT_FLD_LAST: flda0200: 'FLDA0200');
            if (isOK);
               msg = f_newMsg('CPF9897'
                              : 'Last field ' + %trim(flda0200.name) +
                                ', REFFLD(' + %trim(FLDA0200.REFFLD) + ')');
               f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
            else;
               msg = f_newMsg('CPF9898'
                              : 'Failed retrieving attributes of last field'
                              : cMSG_ESCAPE);
               leave;
            endif;

         enddo;

         // Close dictionary
         isOK = f_FldDct_delete(handle);

         if (errMsg.ID <> cMSG_ID_OK);
            f_sndPgmMsg(errMsg: cMsg_Prv: cMsg_ToCtlBdy);
         endif;

         return;

      /END-FREE
      *
     P                 E
