/END-FREE * *==================================================================* * Main procedure *==================================================================* P main... P B export D PI D i_file 10A const D i_fldName 10A const * * Local fields D isOK S N inz D handle S like(fldDct_handle_t) inz * D msg DS likeds(msg_t ) inz D errMsg DS likeds(msg_t ) inz D flda0340 DS likeds(flda0340_t ) inz D default S 128A based(flda0340.pDftValue) *------------------------------------------------------------------- /FREE
errMsg = f_newMsg(cMSG_ID_OK);
dou '1';
// Open dictionary isOK = f_fldDct_new(i_file: '*LIBL': '*FIRST': handle: msg);
// Get attributes of i_fldName isOK = f_FldDct_rtvFldAtr(handle: i_fldName: flda0340: 'FLDA0340'); if (isOK); select; when (flda0340.isNullDft); msg = f_newMsg('CPF9897' : 'Field ' + %trim(flda0340.name) + ', Default is NULL'); when (flda0340.isCurrTime); msg = f_newMsg('CPF9897' : 'Field ' + %trim(flda0340.name) + ', Default is CURRENT_TIME'); when (flda0340.hasDtfKeyword); if (%subst(default: 1: flda0340.lenDftValue) = 'USER'); msg = f_newMsg('CPF9897' : 'Field ' + %trim(flda0340.name) + ', Default is CURRENT_USER'); else; msg = f_newMsg('CPF9897' : 'Field ' + %trim(flda0340.name) + ', Default is ' + %subst(default: 1: flda0340.lenDftValue)); endif; other; msg = f_newMsg('CPF9897' : 'Field ' + %trim(flda0340.name) + ', has no default value'); endsl; f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy); else; errMsg = f_newMsg('CPF9898' : 'Field not found' : cMSG_ESCAPE); leave; endif;
enddo;
// Close dictionary isOK = f_FldDct_delete(handle);
if (errMsg.ID <> cMSG_ID_OK); f_sndPgmMsg(errMsg: cMsg_Prv: cMsg_ToCtlBdy); endif;
return;
